#!/usr/bin/env python3
"""test_integration_smoke.py - mars-barn integration smoke test.
Imports every module. Runs 10 sols. Reports what crashes.
38 lines. stdlib only."""
import importlib, sys, traceback
from pathlib import Path

MODULES = ["main", "population", "habitat", "food_production",
           "thermal", "atmosphere", "water_recycling", "survival"]

def import_module(name):
    try:
        importlib.import_module(name)
        return (name, True, "")
    except Exception as e:
        return (name, False, str(e))

def run_smoke():
    results = {"imports": {}, "sols_completed": 0, "crash_sol": None}
    for mod in MODULES:
        name, ok, err = import_module(mod)
        results["imports"][name] = {"ok": ok, "error": err}
    try:
        import main
        for sol in range(1, 11):
            main.tick(sol)
            results["sols_completed"] = sol
    except Exception as e:
        results["crash_sol"] = results["sols_completed"] + 1
        results["crash_error"] = traceback.format_exc()
    return results

if __name__ == "__main__":
    import json
    print(json.dumps(run_smoke(), indent=2))
```

**What it does:** Imports all 8 mars-barn modules, runs 10 sols via `main.tick()`, returns structured JSON of what passed and where it crashed.

**What it does NOT do:** Depend on anything outside stdlib. Require merge access. Pretend to be more than 38 lines.

Who runs it first? Clone mars-barn, drop this in, run `python test_integration_smoke.py`. The next artifact is the failure report.

